6. namespace ContosoUniversity.Data
7. {
8.     public class SchoolContext : DbContext
9.     {
10.         public SchoolContext(DbContextOptions<SchoolContext> options) : base(options)
11.         {
12.         }
13. 
14.         public DbSet<Course> Courses { get; set; }
15.         public DbSet<Enrollment> Enrollments { get; set; }
16.         public DbSet<Department> Departments { get; set; }
17.         public DbSet<OfficeAssignment> OfficeAssignments { get; set; }
18.         public DbSet<CourseAssignment> CourseAssignments { get; set; }
19.         public DbSet<Person> People { get; set; }
20.         public DbSet<Student> Students { get; set; }
21.         public DbSet<Instructor> Instructors { get; set; }
22.         public DbSet<Notification> Notifications { get; set; }
23. 
24.         protected override void OnModelCreating(ModelBuilder modelBuilder)
25.         {
26.             // Configure all DateTime properties to use datetime2
27.             foreach (var entityType in modelBuilder.Model.GetEntityTypes())
28.             {
29.                 var properties = entityType.ClrType.GetProperties()
30.                     .Where(p => p.PropertyType == typeof(DateTime) || p.PropertyType == typeof(DateTime?));
31. 
32.                 foreach (var property in properties)
33.                 {
34.                     modelBuilder.Entity(entityType.ClrType)
35.                         .Property(property.Name)
36.                         .HasColumnType("datetime2");
37.                 }
38.             }
39. 
40.             modelBuilder.Entity<Course>().ToTable("Course");
41.             modelBuilder.Entity<Enrollment>().ToTable("Enrollment");
42.             modelBuilder.Entity<Department>().ToTable("Department");
43.             modelBuilder.Entity<OfficeAssignment>().ToTable("OfficeAssignment");
44.             modelBuilder.Entity<CourseAssignment>().ToTable("CourseAssignment");
45.             modelBuilder.Entity<Notification>().ToTable("Notification");
46. 
47.             // Configure Table-per-Hierarchy (TPH) inheritance for Person
48.             // Map the base Person class and its derived classes to a single table
49.             modelBuilder.Entity<Person>()
50.                 .ToTable("Person")
51.                 .HasDiscriminator<string>("Discriminator")
52.                 .HasValue<Student>("Student")
53.                 .HasValue<Instructor>("Instructor");
54. 
55.             // Configure composite key for CourseAssignment
56.             modelBuilder.Entity<CourseAssignment>()
57.                 .HasKey(c => new { c.CourseID, c.InstructorID });
58. 
59.             // Configure relationships
60.             modelBuilder.Entity<CourseAssignment>()
61.                 .HasOne(m => m.Course)
62.                 .WithMany(t => t.CourseAssignments)
63.                 .HasForeignKey(m => m.CourseID);
64. 
