namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestDbHelper.CreateSeededContext();
            _controller = new DepartmentsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_WithValidId_ReturnsViewResult()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal("Engineering", model.Name);
        }

        [Fact]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(99999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Get_ReturnsView()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            var department = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = DateTime.Parse("2020-01-01")
            };

            var result = _controller.Create(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.True(_context.Departments.Any(d => d.Name == "Physics"));
        }

        [Fact]
        public void Create_Post_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department();

            var result = _controller.Create(department) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_WithValidId_ReturnsViewResult()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal(1, model.DepartmentID);
        }

        [Fact]
        public void Edit_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(99999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            var dept = _context.Departments.Find(1);
            _context.Entry(dept).State = EntityState.Detached;

            var editedDept = new Department
            {
                DepartmentID = 1,
                Name = "Updated Engineering",
                Budget = 400000,
                StartDate = dept.StartDate
            };

            var result = _controller.Edit(editedDept) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department { DepartmentID = 1 };

            var result = _controller.Edit(department) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Delete_Get_WithValidId_ReturnsViewResult()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal(1, model.DepartmentID);
        }

        [Fact]
        public void Delete_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(99999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesDepartmentAndRedirects()
        {
            var initialCount = _context.Departments.Count();

            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(initialCount - 1, _context.Departments.Count());
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }
    }
}

