using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            _context = TestDbHelper.CreateSeededContext();
            _controller = new NotificationsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void GetNotifications_ReturnsJsonWithSuccessTrue()
        {
            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            var json = result.Value;
            Assert.NotNull(json);
            // Use reflection to check the anonymous object
            var successProp = json.GetType().GetProperty("success");
            Assert.NotNull(successProp);
            Assert.True((bool)successProp.GetValue(json));
        }

        [Fact]
        public void GetNotifications_ReturnsQueuedNotifications()
        {
            // Send a notification via the base controller's notification service
            // The NotificationsController has its own notificationService instance
            // We access it indirectly through the controller's behavior
            var result = _controller.GetNotifications();
            var json = result.Value;
            var countProp = json.GetType().GetProperty("count");
            Assert.NotNull(countProp);
            var count = (int)countProp.GetValue(json);
            Assert.True(count >= 0);
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccessJson()
        {
            var result = _controller.MarkAsRead(1);

            Assert.NotNull(result);
            var json = result.Value;
            var successProp = json.GetType().GetProperty("success");
            Assert.NotNull(successProp);
            Assert.True((bool)successProp.GetValue(json));
        }

        public void Dispose()
        {
