using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestDbHelper.CreateContext();
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };
            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.First(s => s.LastName == "Student");
            Assert.Equal("Test", retrieved.FirstMidName);
            Assert.Equal("Student", retrieved.LastName);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors.First(i => i.LastName == "Instructor");
            Assert.Equal("Test", retrieved.FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveDepartment()
        {
            var dept = new Department
            {
                Name = "Science",
                Budget = 500000,
                StartDate = DateTime.Parse("2020-01-01")
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var retrieved = _context.Departments.First(d => d.Name == "Science");
            Assert.Equal(500000, retrieved.Budget);
        }

        [Fact]
        public void CanAddAndRetrieveCourse()
        {
            _context.Departments.Add(new Department
            {
                DepartmentID = 10,
                Name = "TestDept",
                Budget = 100000,
                StartDate = DateTime.Parse("2020-01-01")
            });
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 5000,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 10
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var retrieved = _context.Courses.Find(5000);
            Assert.NotNull(retrieved);
            Assert.Equal("Test Course", retrieved.Title);
        }

        [Fact]
        public void CourseAssignment_CompositeKey_Works()
        {
            _context.Departments.Add(new Department
            {
                DepartmentID = 20,
                Name = "Dept",
                Budget = 100000,
                StartDate = DateTime.Now
            });
            _context.SaveChanges();

            var instructor = new Instructor
            {
                FirstMidName = "A",
                LastName = "B",
                HireDate = DateTime.Now
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            _context.Courses.Add(new Course { CourseID = 6000, Title = "C1", Credits = 3, DepartmentID = 20 });
            _context.SaveChanges();

            var ca = new CourseAssignment { CourseID = 6000, InstructorID = instructor.ID };
            _context.CourseAssignments.Add(ca);
            _context.SaveChanges();

            var retrieved = _context.CourseAssignments.Find(6000, instructor.ID);
            Assert.NotNull(retrieved);
        }

        [Fact]
        public void Enrollment_NavigationProperties_Work()
        {
            _context.Departments.Add(new Department
            {
                DepartmentID = 30,
                Name = "Dept30",
                Budget = 100000,
                StartDate = DateTime.Now
            });
            _context.SaveChanges();

            _context.Courses.Add(new Course { CourseID = 7000, Title = "NavTest", Credits = 3, DepartmentID = 30 });
            var student = new Student { FirstMidName = "Nav", LastName = "Test", EnrollmentDate = DateTime.Now };
            _context.Students.Add(student);
            _context.SaveChanges();

            _context.Enrollments.Add(new Enrollment
            {
                CourseID = 7000,
                StudentID = student.ID,
                Grade = Grade.A
            });
            _context.SaveChanges();

            var enrollment = _context.Enrollments
                .Include(e => e.Course)
                .Include(e => e.Student)
                .First(e => e.StudentID == student.ID);

            Assert.Equal("NavTest", enrollment.Course.Title);
            Assert.Equal("Test", enrollment.Student.LastName);
        }

        [Fact]
        public void OfficeAssignment_OneToOne_Works()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Office",
                LastName = "Test",
                HireDate = DateTime.Now
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            _context.OfficeAssignments.Add(new OfficeAssignment
            {
                InstructorID = instructor.ID,
                Location = "Room 101"
            });
            _context.SaveChanges();

            var retrieved = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .First(i => i.ID == instructor.ID);
            Assert.NotNull(retrieved.OfficeAssignment);
            Assert.Equal("Room 101", retrieved.OfficeAssignment.Location);
        }

        [Fact]
        public void Person_FullName_ReturnsLastNameCommaFirst()
        {
            var student = new Student
            {
                FirstMidName = "John",
                LastName = "Doe",
                EnrollmentDate = DateTime.Now
            };

            Assert.Equal("Doe, John", student.FullName);
        }

        [Fact]
        public void CanAddAndRetrieveNotification()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test notification",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            };
            _context.Notifications.Add(notification);
            _context.SaveChanges();

            var retrieved = _context.Notifications.First();
            Assert.Equal("Test notification", retrieved.Message);
            Assert.False(retrieved.IsRead);
        }

        public void Dispose()
        {
            _context?.Dispose();
        }
    }
}

