using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_SeedsAllEntities()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(Guid.NewGuid().ToString())
                .Options;

            using var context = new SchoolContext(options);
            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
            Assert.Equal(5, context.Instructors.Count());
            Assert.Equal(4, context.Departments.Count());
            Assert.Equal(7, context.Courses.Count());
            Assert.True(context.Enrollments.Any());
            Assert.True(context.CourseAssignments.Any());
            Assert.True(context.OfficeAssignments.Any());
        }

        [Fact]
        public void Initialize_IsIdempotent()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(Guid.NewGuid().ToString())
                .Options;

            using var context = new SchoolContext(options);
            DbInitializer.Initialize(context);
            var studentCount = context.Students.Count();

            // Run again - should not duplicate data
            DbInitializer.Initialize(context);
            Assert.Equal(studentCount, context.Students.Count());
        }

        [Fact]
        public void Initialize_SetsCorrectRelationships()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(Guid.NewGuid().ToString())
                .Options;

            using var context = new SchoolContext(options);
            DbInitializer.Initialize(context);

            // Departments have administrators
            var depts = context.Departments.Include(d => d.Administrator).ToList();
            Assert.All(depts, d => Assert.NotNull(d.InstructorID));

            // Courses belong to departments
            var courses = context.Courses.Include(c => c.Department).ToList();
            Assert.All(courses, c => Assert.NotNull(c.Department));
        }

        [Fact]
        public void Initialize_CreatesEnrollmentsWithGrades()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(Guid.NewGuid().ToString())
                .Options;

            using var context = new SchoolContext(options);
            DbInitializer.Initialize(context);

            var enrollments = context.Enrollments.ToList();
            Assert.True(enrollments.Count >= 11);
            // Some enrollments have grades, at least one doesn't
            Assert.Contains(enrollments, e => e.Grade != null);
            Assert.Contains(enrollments, e => e.Grade == null);
        }
    }
}

