[Fact]
public void Index_WithInstructorIdAndCourseId_SetsViewBagCourseID()
{
    // Seed an instructor with complete navigation chain for InMemory
    var dbName = Guid.NewGuid().ToString();
    using var context = TestDbHelper.CreateContext(dbName);

    var dept = new Department { DepartmentID = 100, Name = "Test", Budget = 1000, StartDate = DateTime.Now };
    context.Departments.Add(dept);
